import{_ as i,c as a,o as e,ah as n}from"./chunks/framework.C-x9UAyH.js";const k=JSON.parse('{"title":"Comandos para el uso de Sinónimos en Oracle","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"oracle/sinonimos.md","filePath":"oracle/sinonimos.md","lastUpdated":1735432879000}'),o={name:"oracle/sinonimos.md"};function l(t,s,p,r,d,c){return e(),a("div",null,[...s[0]||(s[0]=[n('<h1 id="comandos-para-el-uso-de-sinonimos-en-oracle" tabindex="-1">Comandos para el uso de Sinónimos en Oracle <a class="header-anchor" href="#comandos-para-el-uso-de-sinonimos-en-oracle" aria-label="Permalink to &quot;Comandos para el uso de Sinónimos en Oracle&quot;">​</a></h1><p>Los sinónimos son <strong>alias o nombres alternativos</strong> para objetos de base de datos como tablas, vistas, secuencias, procedimientos almacenados, funciones, paquetes u otros sin necesidad de especificar su nombre completamente calificado (esquema.nombre_objeto). Los sinónimos <strong>simplifican el acceso</strong> a estos objetos, especialmente cuando pertenecen a otro esquema o base de datos.</p><p>Un sinónimo es un nombre alternativo para un objeto de la base de datos que se puede usar en lugar del nombre real del objeto. Existen dos tipos principales:</p><ol><li>Sinónimos públicos: Accesibles por todos los usuarios de la base de datos.</li><li>Sinónimos privados: Accesibles solo por el usuario que los crea.</li></ol><h2 id="crear-un-sinonimo" tabindex="-1">Crear un sinónimo <a class="header-anchor" href="#crear-un-sinonimo" aria-label="Permalink to &quot;Crear un sinónimo&quot;">​</a></h2><ol><li>Sinónimo Privado</li></ol><div class="tip custom-block"><p class="custom-block-title">Sintaxis</p><p>CREATE SYNONYM nombre_sinonimo FOR esquema.nombre_objeto;</p></div><ul><li>Crear un sinónimo privado para la tabla ventas en el esquema comercial:</li></ul><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">CREATE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> SYNONYM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ventas_alias </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FOR</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> comercial</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ventas</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><ol start="2"><li>Sinónimo Público</li></ol><div class="tip custom-block"><p class="custom-block-title">Sintaxis</p><p>CREATE PUBLIC SYNONYM nombre_sinonimo FOR esquema.nombre_objeto;</p></div><ul><li>Crear un sinónimo público para una vista llamada productos_view:</li></ul><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">CREATE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> PUBLIC </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SYNONYM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> productos_alias </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FOR</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> comercial</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">productos_view</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><h2 id="eliminar-un-sinonimo" tabindex="-1">Eliminar un sinónimo <a class="header-anchor" href="#eliminar-un-sinonimo" aria-label="Permalink to &quot;Eliminar un sinónimo&quot;">​</a></h2><ol><li>Sinónimo privado</li></ol><div class="tip custom-block"><p class="custom-block-title">Sintaxis</p><p>DROP SYNONYM nombre_sinonimo;</p></div><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">DROP</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> SYNONYM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ventas_alias;</span></span></code></pre></div><ol start="2"><li>Sinónimo público</li></ol><div class="tip custom-block"><p class="custom-block-title">Sintaxis</p><p>DROP PUBLIC SYNONYM nombre_sinonimo;</p></div><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">DROP</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> PUBLIC </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SYNONYM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> productos_alias;</span></span></code></pre></div>',20)])])}const m=i(o,[["render",l]]);export{k as __pageData,m as default};
